var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"섹터 클리어.","JPN":"セクタークリア。","ENG":"Sector clear.","TWN":" 防區清理完畢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"보관소로 모여든 침식체는 전부 처리한 것 같아.","JPN":"保管所に集まった侵食体はこれで全部倒せたようです。","ENG":"Looks like we took down all the C.O.s that gathered at the depot.","TWN":"似乎已經清除所有在保管所聚集的侵蝕體了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_QM","text":{"KOREA":"흐음, 어디서 많이 본 지뢰인가 했더니, 거미 부대의 생존자잖아?","JPN":"ふーん、どこかで見たことある地雷だと思ったら、クモ部隊の生き残りか。","ENG":"Hmm. I thought those mines looked familiar. A survivor from the Arachnid, right?","TWN":"哼，我還說在哪裡見這個地雷，原來是蜘蛛部隊的倖存者啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_QM","text":{"KOREA":"그 녀석들 전부 죽고, 배신자들은 스캐빈저가 되었다 들었는데.","JPN":"あいつらって全員くたばって、裏切り者はスカベンジャーになったと聞いたが。","ENG":"I heard the rest died, and the traitors turned to Scavengers.","TWN":"我記得那群傢伙不是全死，就是叛變後變成清道夫了吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"설마 알파트릭스의 개가 되어 있을 줄은.","JPN":"まさかアルファトリックスの犬になっていたとはな。","ENG":"Never thought you'd end up as Alphatrix's dog.","TWN":"沒想到你會成了阿爾法崔克斯的走狗。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그렇게 서로 잡아먹고 파멸한 주제에 다시 가족이라도 필요했나?","JPN":"あれだけ共食いして破滅したくせに、また家族が欲しくなったのか？","ENG":"After tearing each other apart to ruin, did you need a family again?","TWN":"彼此殘殺、敗亡的你們，現在又需要家人了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"먼 과거의 일이죠.","JPN":"遠い過去のことです。","ENG":"That was a long time ago.","TWN":"那是很久以前的事了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그쪽 해적들의 폭탄 목걸이보다는 개목줄이 훨씬 낫거든요.","JPN":"あなたたち海賊がつけている爆弾付きの首輪よりは、犬の首輪の方が遥かにマシですからね。","ENG":"I'd take a collar any day over the bomb necklaces your pirates wear.","TWN":"比起你們海盜那種炸彈項鍊，狗鍊還舒服多了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하! 그냥 개가 아니라 도사견이었군.","JPN":"は！　ただの犬じゃなくて闘犬だったか。","ENG":"Ha! Turns out you're not just some dog, but a Tosa bred for the fight.","TWN":"哈！原來不只是狗，還是訓練有素的土佐鬥犬啊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"회장이 참 좋은 개목줄을 달아줬나 봐?","JPN":"会長がさぞ立派な首輪をくれたんだろうな。","ENG":"The President must have given you a very fine collar, no?","TWN":"會長給你的狗鍊看來挺高級的嘛？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"툭하면 터져나가는 당신들 모가지보다는 몇백 배 낫죠.","JPN":"日常的に落とされるあなたたちの首よりは数百倍立派ですね。","ENG":"Still hundreds of times better than necks that blow off at the slightest nudge.","TWN":"總比你們動不動就爆炸的脖子好上幾百倍。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"뭣하면 그 쓸모없는 머리통을 용도에 맞게 터트려줄 수 있는데.","JPN":"なんならその使い道のない頭に、爆発というお似合いの結末をお見舞いしてやってもいいのですが。","ENG":"If you want, I can pop that useless head the way it's meant to be used.","TWN":"我一個失手就能把你那沒用的腦袋炸了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그렇게 만들어드릴까요?","JPN":"今からしてあげましょうか？","ENG":"Want me to make it happen?","TWN":"要我幫忙嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그렇게 먼저 싸움을 걸어오면 나야 좋지.","JPN":"先に喧嘩を売ってくれるとはありがたい。","ENG":"If you want to start the fight, that's fine by me.","TWN":"妳先下戰帖的話我當然好啊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"너희들의 거미 지뢰는 내가 꼭 손에 넣어보고 싶었거든.","JPN":"お前たちの蜘蛛型地雷、一度手に入れてみたかったしな。","ENG":"I've been wanting to get my hands on your spider mines.","TWN":"我還真想把你們的蜘蛛地雷弄到手。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그만.","JPN":"そこまでだ。","ENG":"Enough.","TWN":"住手。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"불필요한 대화로 변인을 가하지 마라. 기계수집가.","JPN":"不要な会話で変化の要因を加えるな、機械収集家。","ENG":"Do not cause any unnecessary variables with pointless chatter, Machine Collector.","TWN":"別說廢話增加變數，機械收藏家。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"쳇, 어련하시겠어.","JPN":"ちっ、分かったよ。","ENG":"Tch. As you wish.","TWN":"嘖，你說得都對。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"여기엔 무슨 일로 오신 거죠?","JPN":"ここにはどういった用で？","ENG":"What brings you here?","TWN":"所以你來這裡做什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"우리는 애늙은이의 명령을 받고 여기로 온 거야.","JPN":"俺たちはませガキの命令でここに来た。","ENG":"We came on orders from the old soul.","TWN":"我們是奉那個老頭的命令來的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하필 알파트릭스를 도와줄 줄은 몰랐지만.","JPN":"よりにもよって、アルファトリックスを助けることになるとは知らなかったが。","ENG":"I didn't expect we'd be helping Alphatrix, though.","TWN":"沒想到偏偏會幫到阿爾法崔克斯。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"꽤 질긴 인연이라니까, 안 그래?","JPN":"なかなかの腐れ縁だと思わないか？","ENG":"Talk about a tough bond to break, don't you think?","TWN":"真是糾纏不清的緣分，不是嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"리더가 서브스톰에서 당신들과 한 차례 조우했다는 말은 들었습니다.","JPN":"リーダーがサブストームであなたたちに一度遭遇したという話は聞いています。","ENG":"I heard Leader crossed paths with you once in Substorm.","TWN":"聽說老大在亞爆和你們交過一次手。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"저도 이렇게 냄새나는 작자들일 줄은 몰랐습니다만.","JPN":"私も、こんなに虫唾が走る人たちだとは思いませんでしたが。","ENG":"I didn't expect you to reek this much, though.","TWN":"我也沒想到你們會這麼臭。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"알파트릭스. 보관소의 이터니움을 회수해라.","JPN":"アルファトリックス。保管所のエタニウムを回収しろ。","ENG":"Alphatrix. Recover the Eternium from the depot.","TWN":"阿爾法崔克斯，回收保管所的永恆之金。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"엥? 잠깐, 뭐라고?","JPN":"え？　待って、今なんて？","ENG":"Huh? Wait, what?","TWN":"咦？等等，你剛說什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"우리한테 지금 이터니움을 회수하라고 한 거야?","JPN":"私たちにエタニウムを回収しろって言ったの？","ENG":"Did you just tell us to recover the Eternium?","TWN":"叫我們現在去回收永恆之金？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"우리 이터니움을 약탈하려고 온 게 아니고?","JPN":"あなたたち、エタニウムを奪いに来たんじゃないの？","ENG":"You didn't come to rob us of it?","TWN":"你們不是來搶我們的永恆之金？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래. 너희들, 저 보관소를 확보하는 게 목적이잖아.","JPN":"ああ。お前ら、あの保管所の確保が目的なんだろ。","ENG":"Right. Your goal is to secure that depot.","TWN":"對。你們的目的就是確保那座保管所吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"로터스 관리국을 도와서 방위선을 구축하려는 거 아니야?","JPN":"ロータス管理局と協力して防衛線を構築しようとしてるんだって？","ENG":"You're helping the Lotus Administration build a defense line, aren't you?","TWN":"你們不是要幫洛德斯管理局建立防線嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어, 어떻게 거기까지… 알고 있는 거지?","JPN":"ど、どうしてそこまで……知ってるの？","ENG":"H-how do you... know that?","TWN":"你、你怎麼會知道……那麼多？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"독심술이다, 소녀!","JPN":"読心術能力だ、少女よ！","ENG":"It's mind reading, girl!","TWN":"這是讀心術啊，少女！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"저 악의 무리는 독심술을 익혀 소녀의 머릿속을 헤집고 있는 것이다!","JPN":"あの悪の輩は読心術で少女の頭の中を覗いているのだ！","ENG":"That horde of evil learned mind reading and is rummaging through your head!","TWN":"那群邪惡的人正在用讀心術翻攪你的腦袋！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"흐, 흐에?","JPN":"ふ、ふえ？","ENG":"H-huh?","TWN":"呃、呃咦？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};